noncompliant:
// Noncompliant: Loop counter used in arithmetic operations
for (int i = 0; i + 5 < n; i += 2) {  // i+5 not allowed
    process(array[i]);
}

// Noncompliant: Loop counter used in complex expressions
for (int i = 0; i * 2 != target; ++i) {  // i*2 not allowed
    if (i == max_iterations) break;
}

// Noncompliant: Loop counter used with equality
for (int i = 0; i == stop_value; ++i) {  // == not allowed
    do_work(i);
}

compliant:
// Compliant: Loop counter only used with relational operators
for (int i = 0; i < n; i += 2) {  // Only < comparison
    process(array[i]);
}

for (int i = 10; i >= 0; --i) {  // Only >= comparison
    countdown[i] = i;
}

// Compliant: Proper use of comparison operators
for (int i = start; i <= end; ++i) {  // <= is allowed
    data[i] = compute(i);
}

for (int i = max; i > min; i--) {  // > is allowed
    process_backwards(i);
}
